#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long cnt1=0, cnt2=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x==1) cnt1++;
            else if(x==2) cnt2++;
        }
        long long ans = cnt1 * (N - cnt1) + cnt1*(cnt1-1)/2 + cnt2*(cnt2-1)/2;
        printf("%lld\n", ans);
    }
    return 0;
}

