import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cnt1 = cnt2 = 0
        for _ in range(N):
            x = int(next(it))
            if x == 1:
                cnt1 += 1
            elif x == 2:
                cnt2 += 1
        ans = cnt1 * (N - cnt1) + cnt1 * (cnt1 - 1) // 2 + cnt2 * (cnt2 - 1) // 2
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

